INSERT INTO `wts_material` (`ID`, `CTIME`, `ETIME`, `CUSER`, `EUSER`, `PSTATE`, `PCONTENT`, `TEXT`, `TITLE`, `UUID`) VALUES
	('2c902a8d70319d80017031ebe6d60015', '20200211094508', '20210311204224', '40288b854a329988014a329a12f30002', '40288b854a329988014a329a12f30002', '1', NULL, '<p style="text-align:center;">\r\n	路边的小花在瑟瑟的寒风中\r\n</p>\r\n<p style="text-align:center;">\r\n	谦卑地开放了\r\n</p>\r\n<p style="text-align:center;">\r\n	仿佛大地做了一个小小的梦\r\n</p>\r\n<p style="text-align:center;">\r\n	纤弱的身影\r\n</p>\r\n<p style="text-align:center;">\r\n	投在深黑的土地上\r\n</p>\r\n<p style="text-align:center;">\r\n	沉默的微笑\r\n</p>\r\n<p style="text-align:center;">\r\n	温柔了整个世界\r\n</p>\r\n<div style="text-align:center;">\r\n	那几片单纯的花瓣\r\n</div>\r\n<div style="text-align:center;">\r\n	竟一下子使行者的眼眶涌满了泪水\r\n</div>\r\n<p style="text-align:center;">\r\n	开了又枯萎了\r\n</p>\r\n<div style="text-align:center;">\r\n	路边的小花\r\n</div>\r\n<div style="text-align:center;">\r\n	仿佛大地做了又一个小小的梦\r\n</div>\r\n<p style="text-align:center;">\r\n	<img src="actionImg/Publoadimg.do?id=2c91808c77cceb5c0177f68c4c24064b&type=max" title="粘贴图片" alt="粘贴图片" width="211" height="235" align="" />\r\n</p>', '暖色的梦', '2c902a8d70319d80017031ebe6d60015');
