INSERT INTO `wts_room_scoreeval` (`ID`, `NAME`, `POINTS`, `POINTE`, `DESCRIBES`, `PAPERID`, `ROOMID`, `NOTE`) VALUES
	('2c91808c8fa0889f018fa0eb82962809', '不及格', 0, 1, '', '', '2c902a8d702e542901702ea293330263', ''),
	('2c91808c8fa0889f018fa0ebb81e280a', '及格', 2, 3, '', '', '2c902a8d702e542901702ea293330263', ''),
	('2c91808c8fa0889f018fa0ebdd0b280b', '优秀', 3, 8, '', '', '2c902a8d702e542901702ea293330263', ''),
	('2c91808c8fa0889f018fa0ec8a4d280c', '平凡', 0, 30, '', '', '2c902a8d751cff5b01751d1f96cf0092', ''),
	('2c91808c8fa0889f018fa0eccecd280d', '可期', 31, 60, '', '', '2c902a8d751cff5b01751d1f96cf0092', ''),
	('2c91808c8fa0889f018fa0ecfe6f280e', '卓越', 61, 100, '', '', '2c902a8d751cff5b01751d1f96cf0092', ''),
	('2c91808c8fa8f177018fa92ee7801adf', '差', 0, 10, '&quot;这次数学答卷反映出你在理解和应用数学概念上存在较大困难。许多基础计算出现错误，解题思路不够清晰，表明目前的学习状态需要紧急调整。建议你首先回顾并巩固数学的基本概念和运算规则，确保每个知识点都真正理解并能熟练应用。同时，考虑寻求老师或同学的帮助，参加课外辅导或者利用在线资源进行额外练习。重要的是要建立起一个系统的学习计划，设定可达成的小目标，逐步提升自信心和解题能力。请记住，每个人的进度不同，遇到困难时不要气馁，坚持就是胜利。&quot;', '', '2c91808c8fa8f177018fa92e17491ada', ''),
	('2c91808c8fa8f177018fa92f10dc1ae0', '中', 11, 20, '&quot;从这次的数学测试来看，你在一些核心概念的理解和应用上还有待加强。部分题目出现了基本计算错误，表明在基础技能上需要更多练习。同时，解题过程中缺乏清晰的步骤说明，这可能影响了你对问题的全面分析。建议花时间复习基础数学概念，特别是那些你觉得不够牢固的部分，并通过大量练习来提高解题的准确性和速度。此外，尝试在解题时分步写下思考过程，这有助于理清思路并发现潜在的错误。请记住，持之以恒的努力是提高成绩的关键。&quot;', '', '2c91808c8fa8f177018fa92e17491ada', ''),
	('2c91808c8fa8f177018fa92f450b1ae1', '良', 21, 70, '&quot;这次的数学作业反映出你对大部分基础概念有较好的掌握，但在一些进阶问题上似乎遇到了些小障碍。你的计算过程基本正确，但缺乏一些问题解决策略的多样性。建议在接下来的学习中，多尝试不同的解题方法，加强逻辑推理训练，并且不要害怕挑战自己不熟悉或感到困难的题目。通过持续练习和主动探索，相信你能进一步提升自己的数学能力。&quot;', '', '2c91808c8fa8f177018fa92e17491ada', ''),
	('2c91808c8fa8f177018fa92f71b91ae2', '优', 71, 150, '&quot;本次数学测验中，你展现出了卓越的逻辑思维能力和深刻的概念理解。你的解题步骤清晰、准确，尤其是在解决复杂问题时的创新思路令人印象深刻。对公式的灵活运用和计算的准确性体现了你扎实的基础和良好的学习习惯。继续保持这种高水平的学习态度，不断挑战更高难度的问题，相信你会在数学领域取得更加辉煌的成就。&quot;', '', '2c91808c8fa8f177018fa92e17491ada', '');
