INSERT INTO `wts_subject_analysis` (`ID`, `CTIME`, `CUSERNAME`, `PSTATE`, `CUSER`, `PCONTENT`, `TEXT`, `SUBJECTID`) VALUES
	('2c902a8d70319d80017031edce720019', '20200211094713', '系统管理员', '1', '40288b854a329988014a329a12f30002', '批量导入', '认真品读诗歌,体悟诗歌内涵；仔细阅读题目,结合诗歌内容,发挥想象,组织语言表达.\r\n', '2c902a8d70319d80017031edce720016'),
	('2c902a8d70319d80017031edce82001d', '20200211094713', '系统管理员', '1', '40288b854a329988014a329a12f30002', '批量导入', '认真品读诗歌,体悟诗歌内涵；仔细阅读题目,结合诗歌内容,发挥想象,组织语言表达.', '2c902a8d70319d80017031edce72001a'),
	('2c902a8d751cff5b01751d1a4d5b003c', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '因为大象从属于动物范畴，动物有腿，所以大象也有腿。\r\n\r\n', '2c902a8d751cff5b01751d1a4d5b0038'),
	('2c902a8d751cff5b01751d1a4d6b0041', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '秘书还未到参加选民选举的年龄和有着漂亮的头发没有必然联系。\r\n\r\n', '2c902a8d751cff5b01751d1a4d5b003d'),
	('2c902a8d751cff5b01751d1a4d6b0046', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '所有的商店都有遮蓬，其中有少部分可能又有霓虹灯。\r\n\r\n', '2c902a8d751cff5b01751d1a4d6b0042'),
	('2c902a8d751cff5b01751d1a4d7a004b', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', 'A和B没有必然联系。如：人都有两只眼睛，猪也有两只眼睛，人和猪没有必然关系哈。\r\n\r\n', '2c902a8d751cff5b01751d1a4d6b0047'),
	('2c902a8d751cff5b01751d1a4d7a0050', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '因为西红柿比土豆贵，所以钱肯定不够买两磅西红柿，可能够买一磅也可能不够。\r\n\r\n', '2c902a8d751cff5b01751d1a4d7a004c'),
	('2c902a8d751cff5b01751d1a4d8a0056', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '韦利·美斯和斯坦·茂斯尔水平相当，斯坦·茂斯尔比大多数人都要强，所以韦利·美斯也比比大多数人都要强。\r\n\r\n', '2c902a8d751cff5b01751d1a4d7a0051'),
	('2c902a8d751cff5b01751d1a4d8a005b', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '演奏古典音乐和演奏爵士乐没有必然关系\r\n\r\n', '2c902a8d751cff5b01751d1a4d8a0057'),
	('2c902a8d751cff5b01751d1a4d990061', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '原命题成立，则逆否命题成立。正方形有角，则没角的图形不是正方形。\r\n\r\n', '2c902a8d751cff5b01751d1a4d8a005c'),
	('2c902a8d751cff5b01751d1a4d990066', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '孩子被宠坏或没被宠坏，两者必有其一，所以打他屁股会使他发怒或者会使你懊悔必有其一。\r\n\r\n', '2c902a8d751cff5b01751d1a4d990062'),
	('2c902a8d751cff5b01751d1a4da9006c', '20201012215744', '系统管理员', '1', '2c902a8d75168c9f0175168cf5540000', '批量导入', '因为纽约在史密斯城的东北，所以史密斯城在纽约的西南。', '2c902a8d751cff5b01751d1a4d990067'),
	('2c91808c8fa8f177018fa9277ee419c8', '20240524135128', '系统管理员', '1', '40288b854a329988014a329a12f30002', '[NONE]', '<img  width="302"  height="41"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ee419c6&type=max" alt="" /><br /><img  width="205"  height="63"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ee419c7&type=max" alt="" />', '2c91808c8fa8f177018fa9277ed519c3'),
	('2c91808c8fa8f177018fa9277ef419d2', '20240524135129', '系统管理员', '1', '40288b854a329988014a329a12f30002', '[NONE]', '<img  width="148"  height="41"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ef419d0&type=max" alt="" />，<br /><img  width="263"  height="41"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ef419d1&type=max" alt="" />', '2c91808c8fa8f177018fa9277ef419cd'),
	('2c91808c8fa8f177018fa9277ed519c0', '20240524135128', '系统管理员', '1', '40288b854a329988014a329a12f30002', '[NONE]', '<img  width="278"  height="63"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ec519bd&type=max" alt="" />，(A)不对；<br /><img  width="288"  height="63"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ed519be&type=max" alt="" />，(B)不对；<br /><img  width="516"  height="63"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ed519bf&type=max" alt="" />，<br />应选(C).', '2c91808c8fa8f177018fa9277eb519b7'),
	('2c91808c8fa8f177018fa9277ea619ad', '20240524135128', '系统管理员', '1', '40288b854a329988014a329a12f30002', '[NONE]', '令<img  width="549"  height="21"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277e9619a7&type=max" alt="" />，<br />即<img  width="529"  height="63"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277e9619a8&type=max" alt="" />，<br />若<img  width="60"  height="21"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277e9619a9&type=max" alt="" />，从而<img  width="121"  height="21"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ea619aa&type=max" alt="" />，<br />即<img  width="53"  height="21"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ea619ab&type=max" alt="" />的解均为<img  width="53"  height="21"  src="actionImg/Publoadimg.do?id=2c91808c8fa8f177018fa9277ea619ac&type=max" alt="" />的解，应选(D).', '2c91808c8fa8f177018fa9277e8719a1'),
